            var opts = {
                id : "smpPop"
                , popupName : "인력검색"
                , modal : true
                , type : "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
                , title : "Win pop"  //Layer pop
                , width : 700
                , height : 450
            };

            rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml", opts, arrParam);

            //(0)직종코드		
