            //(10)배치가능여부	
            //(11)본사계약직여부 
            //(12)연근여부		

            if (rtnList != null) {
                ed_staffNo.setValue(rtnList[2]);	//사원코드
                txt_staffNm.setValue(rtnList[3]);	//사원명
            } else {
                ed_staffNo.setValue("");	//사원코드
                txt_staffNm.setValue("");	//사원명
            }

            break;

        case 3:	
            if (!await $c.gus.cfValidate(ed_branCd)) {
                return;
            }

            var pWhere = "";
            var lobranCd = "";
            var occptypeCd = "";
            var dtlOccpTypeCd = "";

            lobranCd = ed_branCd.getValue();
            pWhere = lobranCd;
            //3: lobranCd  //점소
