                                    ,null
                                    ,null
                                    ,null
                                    ,pWhere   //
                                    ,null
                                    ,null
                                    ,null);

                                        //사번  인원명
            cfSetReturnValue(rtnList, ed_staffNo, txt_staffNm);
            break;
    }	
};

